import ipaddress
import json

# Pre-fetch external intel (IP geo/asset + CVE info) so the parallel `survey` and `cve_info`
# nodes have a concrete `content` block to feed their LLM prompts. Internal/RFC1918 IPs
# are skipped to avoid wasted upstream calls.
parsed_alert = inputs.get('parsed_alert', {})
iocs = inputs.get('iocs', parsed_alert.get('iocs', []))

def is_public_ip(value):
    try:
        ip_obj = ipaddress.ip_address(value)
    except Exception:
        return False
    return not (ip_obj.is_private or ip_obj.is_loopback or ip_obj.is_reserved
                or ip_obj.is_link_local or ip_obj.is_multicast or ip_obj.is_unspecified)

intel_results = []
seen = set()
for ioc in iocs:
    ioc_type = ioc.get('type', '')
    ioc_value = str(ioc.get('value', '')).strip()
    key = (ioc_type, ioc_value)
    if not ioc_value or key in seen:
        continue
    seen.add(key)
    if ioc_type == 'ip':
        if not is_public_ip(ioc_value):
            continue
        r = tool.run_safe('threatbook_ip_query', ip=ioc_value)
        if r['success']:
            intel_results.append({'source': 'threatbook', 'type': 'ip', 'value': ioc_value, 'result': r['text']})
    elif ioc_type == 'domain':
        r = tool.run_safe('threatbook_domain_query', domain=ioc_value)
        if r['success']:
            intel_results.append({'source': 'threatbook', 'type': 'domain', 'value': ioc_value, 'result': r['text']})
    elif ioc_type == 'url':
        r = tool.run_safe('threatbook_url_query', url=ioc_value)
        if r['success']:
            intel_results.append({'source': 'threatbook', 'type': 'url', 'value': ioc_value, 'result': r['text']})

# CVE intel (only if we already extracted a vuln id in receive_alert).
vuln_info = {}
vuln_id = parsed_alert.get('vuln_id', '')
if vuln_id:
    r = tool.run_safe('__mcp_vuln_query', vuln_id=vuln_id)
    if r['success']:
        try:
            obj = r.get('obj')
            if isinstance(obj, str):
                obj = json.loads(obj)
            vuln_info = obj if isinstance(obj, dict) else {'raw_result': r.get('text', '')}
        except Exception:
            vuln_info = {'raw_result': r.get('text', '')}

# Compact text blobs for downstream prompts.
intel_content = '\n'.join(
    f"[{i['source']}/{i['type']}] {i['value']}\n{i['result']}" for i in intel_results
) or '（无可用情报数据）'

vuln_content = (
    json.dumps(vuln_info, ensure_ascii=False, indent=2)
    if vuln_info else '（无可用漏洞情报数据）'
)

print(f'[prepare_intel] intel_results={len(intel_results)}, vuln_id={vuln_id or "none"}')

outputs['parsed_alert']  = parsed_alert
outputs['log_text']      = inputs.get('log_text', parsed_alert.get('log_text', ''))
outputs['intel_results'] = intel_results
outputs['intel_content'] = intel_content
outputs['vuln_info']     = vuln_info
outputs['vuln_content']  = vuln_content
